void solve(int CASE)
{
	ll x, y, m, n, L; cin >> x >> y >> m >> n >> L;
	// x + k * m = y + k * n (mod L)
	// x + k * m = y + k * n + k' * L
	// (x + k * m) - (y + k * n) = k' * L
	// (n - m) * k + L * k' = x - y

	ll a = n - m, b = L, c = x - y;
	ll x0, y0;
	ll g = Math::exgcd(abs(a), abs(b), x0, y0); // 对负数进行处理
	if (c % g != 0) {
		cout << "Impossible" << endl;
		return;
	}

	x0 *= c / g, y0 *= c / g;
	if (a < 0)x0 = -x0; // 还原
	if (b < 0)y0 = -y0;
	ll dx = b / g;
	ll ans = (x0 % dx + dx) % dx;
	cout << ans << endl;
	return;
}
